     1→general {
     2→    lock_cmd = omarchy-lock-screen                         # lock screen and 1password
     3→    before_sleep_cmd = loginctl lock-session               # lock before suspend.
     4→    after_sleep_cmd = sleep 1 && hyprctl dispatch dpms on  # delay for PAM readiness, then turn on display.
     5→    inhibit_sleep = 3                                      # wait until screen is locked
     6→}
     7→
     8→listener {
     9→    timeout = 150                                             # 2.5min
    10→    on-timeout = pidof hyprlock || omarchy-launch-screensaver # start screensaver (if we haven't locked already)
    11→}
    12→
    13→listener {
    14→    timeout = 151                      # 5min
    15→    on-timeout = loginctl lock-session # lock screen when timeout has passed
    16→}
    17→
    18→listener {
    19→    timeout = 330                                            # 5.5min
    20→    on-timeout = brightnessctl -sd '*::kbd_backlight' set 0  # save state and turn off keyboard backlight
    21→    on-resume = brightnessctl -rd '*::kbd_backlight'         # restore keyboard backlight
    22→}
    23→
    24→listener {
    25→    timeout = 330                                            # 5.5min
    26→    on-timeout = hyprctl dispatch dpms off                   # screen off when timeout has passed
    27→    on-resume = hyprctl dispatch dpms on && brightnessctl -r # screen on when activity is detected
    28→}
    29→

